const headers = ($json && typeof $json === 'object' && $json.headers && typeof $json.headers === 'object') ? $json.headers : {};
const body = ($json && typeof $json === 'object') ? ($json.body ?? $json) : {};

const getHeader = (name) => {
  const target = String(name).toLowerCase();
  for (const [k, v] of Object.entries(headers)) {
    if (String(k).toLowerCase() === target) return v;
  }
  return undefined;
};

const expectedSecret = $env.TIS_PILOT_SECRET;
if (!expectedSecret || String(expectedSecret).trim() === '') {
  return [{ json: { status:'error', error_type:'config_missing', message:'Missing env var TIS_PILOT_SECRET', details:'', error_http_code:500 } }];
}

const incomingSecret = getHeader('X-TIS-Secret');
if (!incomingSecret || String(incomingSecret).trim() === '' || String(incomingSecret) !== String(expectedSecret)) {
  return [{ json: { status:'error', error_type:'auth_failed', message:'Missing or invalid X-TIS-Secret', details:'', error_http_code:401 } }];
}

if (!body || typeof body !== 'object' || Array.isArray(body)) {
  return [{ json: { status:'error', error_type:'validation_failed', message:'Payload must be a JSON object', details:'Invalid payload shape', error_http_code:400 } }];
}

const asString = (v) => (typeof v === 'string' ? v.trim() : (v === null || v === undefined ? '' : String(v).trim()));

const asUrl = (v) => {
  const s = asString(v);
  if (!s) return '';
  if (s.startsWith('http://') || s.startsWith('https://')) return s;
  return '';
};

const normalizeMediaList = (value, fieldName) => {
  if (value === null || value === undefined) return [];
  if (!Array.isArray(value)) return null;

  const list = [];
  for (const item of value.slice(0, 50)) {
    if (!item || typeof item !== 'object' || Array.isArray(item)) return null;
    const url = asUrl(item.url);
    if (!url) return null;
    const label = asString(item.label);
    const captured_at = asString(item.captured_at);
    list.push({ url, label: label || undefined, captured_at: captured_at || undefined });
  }

  if (fieldName === 'before_photos' && list.length < 1) return null;
  return list;
};

const warnings = [];

const mode = asString(body.mode);
if (mode !== 'pilot_non_production') {
  return [{ json: { status:'error', error_type:'validation_failed', message:'mode must be pilot_non_production', details:'', error_http_code:400 } }];
}

const propertyAddress = asString(body.property_address);
const serviceDate = asString(body.service_date);
const notes = asString(body.notes);

const beforePhotos = normalizeMediaList(body.before_photos, 'before_photos');
const afterPhotos = normalizeMediaList(body.after_photos, 'after_photos');
const documents = normalizeMediaList(body.documents, 'documents');

const missing = [];
if (!propertyAddress) missing.push('property_address');
if (!serviceDate) missing.push('service_date');
if (!notes) missing.push('notes');
if (beforePhotos === null) missing.push('before_photos');

if (missing.length) {
  return [{ json: { status:'error', error_type:'validation_failed', message:'Missing/invalid required fields', details: JSON.stringify({ missing_fields: missing }), error_http_code:400 } }];
}

if (notes.length < 3) warnings.push('notes is very short');

const placeholderPatterns = [
  /\b(tbd|todo)\b/i,
  /\bfill\s+in\b/i,
  /lorem\s+ipsum/i,
  /\bplaceholder\b/i,
];
for (const pat of placeholderPatterns) {
  if (pat.test(propertyAddress)) {
    return [{ json: { status:'error', error_type:'validation_failed', message:'property_address appears to contain placeholder text', details:'', error_http_code:400 } }];
  }
}

const ingestedAt = new Date().toISOString();
const intakeId = `tis-pilot-${Date.now()}`;

const payload = {
  mode,
  job_id: asString(body.job_id) || intakeId,
  customer_name: asString(body.customer_name) || undefined,
  property_address: propertyAddress,
  service_date: serviceDate,
  notes,
  before_photos: beforePhotos,
  after_photos: afterPhotos || [],
  documents: documents || [],
};

const response = {
  status: 'accepted',
  mode,
  message: 'Pilot intake validated',
  intake_id: intakeId,
  job_id: payload.job_id,
  next_step: 'ready_for_report_generation',
  warnings,
  payload,
};

console.log('tis-pilot:intake_ok', { intake_id: intakeId, job_id: payload.job_id });
return [{ json: { status:'pass', intake_id: intakeId, ingested_at: ingestedAt, warnings, payload, response } }];

const validated = $json;

if (!validated || typeof validated !== 'object') {
  return [{ json: { status:'error', error_type:'validation_failed', message:'Invalid internal state', details:'', error_http_code:500 } }];
}

const rootFolderId = $env.TVG_SYSTEM_ROOT_FOLDER_ID;
if (!rootFolderId || String(rootFolderId).trim() === '') {
  return [{ json: { status:'error', error_type:'config_missing', message:'Missing env var TVG_SYSTEM_ROOT_FOLDER_ID', details:'', error_http_code:500 } }];
}

const payload = (validated.payload && typeof validated.payload === 'object') ? validated.payload : {};
const asString = (v) => (typeof v === 'string' ? v.trim() : (v === null || v === undefined ? '' : String(v).trim()));
const safe = (s) => asString(s)
  .replace(/[\\/]/g, '-')
  .replace(/[:*?"<>|]/g, '-')
  .replace(/\s+/g, ' ')
  .trim()
  .slice(0, 80);

const jobId = asString(payload.job_id);
const customerName = asString(payload.customer_name);
const serviceDate = asString(payload.service_date);
const isoDate = /^\d{4}-\d{2}-\d{2}$/;
const datePart = isoDate.test(serviceDate) ? serviceDate : new Date().toISOString().slice(0, 10);
const fallbackFolderName = `${datePart}__${safe(customerName || 'unknown-customer')}`;
const jobFolderName = safe(jobId) || safe(fallbackFolderName);

const intake = {
  job_id: jobId || jobFolderName,
  intake_id: asString(validated.intake_id),
  accepted_at: asString(validated.ingested_at) || new Date().toISOString(),
  customer_name: customerName || null,
  site_address: asString(payload.property_address) || null,
  service_date: asString(payload.service_date) || null,
  status: 'accepted',
  notes: asString(payload.notes) || '',
  before_photos: Array.isArray(payload.before_photos) ? payload.before_photos : [],
  after_photos: Array.isArray(payload.after_photos) ? payload.after_photos : [],
  documents: Array.isArray(payload.documents) ? payload.documents : [],
  source: 'n8n tis-pilot-intake',
};

return [{
  json: {
    status: 'pass',
    drive_root_folder_id: String(rootFolderId).trim(),
    command_center_folder_name: 'Command-Center',
    accepted_intake_folder_name: 'Accepted-Intake',
    job_folder_name: jobFolderName,
    intake_file_name: 'intake.json',
    intake_file_content: JSON.stringify(intake, null, 2) + "\n",
    original_response: validated.response,
  }
}];
